        </div>
      </section>
    </div>
  </section>
</template>

<script setup lang="ts">
import OiIcon from 'src/components/ui/OiIcon.vue'
import type { OiIconName } from 'src/components/ui/OiIcon.vue'
import type {
  StoryWorkflowNodeSummary,
  StoryRunSummary,
} from 'src/components/session-workspace/types'
import { resolveLatestRunStatus } from 'src/utils/story-timeline'
import { formatIsoRelative } from 'src/utils/format-time'

type RunStatus = StoryRunSummary['status']

// ── Props ────────────────────────────────────────────────────────────────────

const props = withDefaults(defineProps<{
  /** Workflow DAG nodes for the current episode. */
  nodes?: StoryWorkflowNodeSummary[]
  /** Generation runs, expected reverse-chronological (newest first). */
  runs?: StoryRunSummary[]
  /** Currently selected node (highlights its card). */
  selectedNodeId?: string | null
  /** Currently selected run (highlights its item). */
  selectedRunId?: string | null
}>(), {
  nodes: () => [],
  runs: () => [],
  selectedNodeId: null,
  selectedRunId: null,
})

const emit = defineEmits<{
  (e: 'node-select', id: string): void
  (e: 'run-select', id: string): void
}>()

// ── Handlers ──────────────────────────────────────────────────────────────────

function onNodeSelect(id: string): void {
  emit('node-select', id)
}

function onRunSelect(id: string): void {
  emit('run-select', id)
}

// ── Label / glyph helpers ─────────────────────────────────────────────────────

function toolIcon(kind: StoryWorkflowNodeSummary['toolKind']): OiIconName {
  switch (kind) {
    case 'image_generate': return 'image-card'
    case 'video_generate': return 'canvas'
    case 'image_edit': return 'enhance-wave'
  }
}

function toolKindLabel(kind: StoryWorkflowNodeSummary['toolKind']): string {
  // TODO(coder): localize via i18n if a translation layer is introduced.
  switch (kind) {
    case 'image_generate': return '图像生成'
    case 'video_generate': return '视频生成'
    case 'image_edit': return '图像编辑'
  }
}

function runStatusLabel(status: RunStatus | 'none'): string {
  // TODO(coder): localize via i18n if a translation layer is introduced.
  switch (status) {
    case 'completed': return '已完成'
    case 'running': return '进行中'
    case 'failed': return '失败'
    case 'queued': return '排队中'
    case 'none': return '未运行'
  }
}

/** Latest-run status for a node, resolved against `runs` by `latestRunId`. */
function latestRunStatus(node: StoryWorkflowNodeSummary): RunStatus | 'none' {
  return resolveLatestRunStatus(node.latestRunId, props.runs)
}

/** Human-readable relative label for a run's start time. */
function formatRunTime(startedAt: string): string {
  return formatIsoRelative(startedAt) || startedAt
}
</script>

